def validate_api_semantic_contracts(contract_path: str) -> int:
    result = _run_snippet(VALIDATE_API_SEMANTIC_CONTRACTS_SNIPPET, [contract_path])
    if result.stdout:
        sys.stdout.write(result.stdout)
    if result.stderr:
        sys.stderr.write(result.stderr)
    return result.returncode

